  CARTS_UPDATE = 'CARTS_UPDATE',
  /** The webhook topic for `channels/delete` events. Occurs whenever a channel is deleted. Requires the `read_publications` scope. */
  CHANNELS_DELETE = 'CHANNELS_DELETE',
